 1	import React, { FC, useState } from 'react';
 2	
 3	import KebabToggle from '@kubevirt-utils/components/toggles/KebabToggle';
 4	import { useKubevirtTranslation } from '@kubevirt-utils/hooks/useKubevirtTranslation';
 5	import { Dropdown, DropdownItem, DropdownList } from '@patternfly/react-core';
 6	
 7	import { AffinityRowData } from '../../../utils/types';
 8	
 9	type AffinityRowActionsDropdownProps = {
10	  affinity: AffinityRowData;
11	  onDelete: (affinity: AffinityRowData) => void;
12	  onEdit: (affinity: AffinityRowData) => void;
13	};
14	
15	const AffinityRowActionsDropdown: FC<AffinityRowActionsDropdownProps> = ({
16	  affinity,
17	  onDelete,
18	  onEdit,
19	}) => {
20	  const { t } = useKubevirtTranslation();
21	  const [isOpen, setIsOpen] = useState(false);
22	
23	  const onToggle = () => setIsOpen((prevIsOpen) => !prevIsOpen);
24	  const handleDelete = () => {
25	    onDelete(affinity);
26	    setIsOpen(false);
27	  };
28	  return (
29	    <Dropdown
30	      isOpen={isOpen}
31	      onOpenChange={(open: boolean) => setIsOpen(open)}
32	      toggle={KebabToggle({ isExpanded: isOpen, onClick: onToggle })}
33	    >
34	      <DropdownList>
35	        <DropdownItem key="edit" onClick={() => onEdit(affinity)}>
36	          {t('Edit')}
37	        </DropdownItem>
38	        <DropdownItem key="delete" onClick={() => handleDelete()}>
39	          {t('Delete')}
40	        </DropdownItem>
41	      </DropdownList>
42	    </Dropdown>
43	  );
44	};
45	
46	export default AffinityRowActionsDropdown;

